insert into meetings (meeting_date,meeting_type,title,attendees,summary) values
('2021-06-18'::date,'mgmt_weekly','檔案命名規則會議 / 知識管理會議',array[]::text[],'黃杰、泓儒、皓明、又仁、棠娜、泰儀；盤點、整理既有工作手冊、檢查表>> 又仁、棠娜、泰儀；初步規劃各部門項下資料夾怎麼設計、目前已有什麼資料>> 又仁、棠娜、泰儀；知識管理重要性：；傳承及確立：知識、理念、流程；統一並提高法律工作品質、效率'),
('2021-07-02'::date,'mgmt_weekly','知識管理_專案管理系統會議',array[]::text[],'請各自報告目前整理狀況；已完成大部分，尚未完成部分，法律知識資料庫：共通、民刑事訴訟部分，黃杰會先行協助完成（110.07.09）；例稿部分預計仍交由于瑾下週完成（110.07.09）。；民事案件僅列本所當事人，或是列本所當事人v對造當事人'),
('2021-07-16'::date,'mgmt_weekly','知識管理_專案管理系統會議',array[]::text[],'皓明、泰儀、黃杰、泓儒、又仁、棠娜；資料夾架構（共同編輯）；確認各分所既有的收發文檔案名稱列名方法(ex 執行名義? 書狀名稱?) 收發文、閱卷資料、本所出狀>> 泰儀'),
('2021-07-30'::date,'mgmt_weekly','主管會議',array[]::text[],'通知北所桃所行政，更新檔名建立規則>> 泰儀；日期_當事人_文書內容；XX企業社即○○○-身分證字號'),
('2021-08-09'::date,'mgmt_weekly','主管會議',array[]::text[],'皓明、泰儀、黃杰、泓儒、又仁、于瑾、棠娜、昭萱、郁萱(1130加入)；說明權限、設定權限>> 泰儀>> 8/16前處理完畢；只開公告+自己部門'),
('2021-08-17'::date,'mgmt_weekly','主管會議',array[]::text[],'行政財務委前法務>> 完成；其他資料夾>> 各分所、主管；(公司名稱)>> 于瑾、偉志建立'),
('2021-08-23'::date,'mgmt_weekly','主管會議',array[]::text[],'「行政事件」當負責人為複數時，會彈窗提醒，勾選已完成時，另一位負責人也會顯示為已完成。；「案件歷程」顯示建立時間（建立人員）;最後更新時間（更新人員） (如為離職人員，將不會顯示)；「庭期」添加到Google時，格式修改，會將真正的時間添加到標題。>'),
('2021-08-30'::date,'mgmt_weekly','主管會議',array[]::text[],'雲端權限設定明細；待追功能修改完成，請又仁、棠娜、于瑾協助移動待追(9/6)；帶入案號（不是系統案號，或法院或地檢署案號！）'),
('2021-09-06'::date,'mgmt_weekly','主管會議',array[]::text[],'案件及當事人（自然人/法人）新增雲端硬碟連結；當事人基本資料>> 連結；案件資料>> 雲端連結'),
('2021-09-13'::date,'mgmt_weekly','主管會議',array[]::text[],'諮詢(未委任前的會議)；現場諮詢（一諮）；大分類+事件類型＋可自行標註書狀標題（例：民事答辯一狀）'),
('2021-09-27'::date,'mgmt_weekly','主管會議',array[]::text[],'諮詢數字不要人工key，直接以系統計算；修改<諮詢後資料表>，增加視訊會議是否有見到，即便只有開視訊10分鐘最後都改為通話，也會勾選為<視訊>；契約/協議書撰擬/審閱'),
('2021-10-04'::date,'mgmt_weekly','主管會議',array[]::text[],'黃杰 泰儀 泓儒 于瑾 棠娜 又仁；事務所資料及知識管理系統：；先生小三案件後續處理辦法>>'),
('2021-10-18'::date,'mgmt_weekly','主管會議',array[]::text[],'皓明 泰儀 泓儒 于瑾 又仁 昭萱；利益衝突同意書 1101014（潘品淳案）.docx；後續處理方式: 請另一個元配不來所'),
('2021-10-25'::date,'mgmt_weekly','主管會議',array[]::text[],'皓明 泰儀 泓儒 于瑾 又仁 昭萱 黃杰 郁萱 棠娜；確認google雲端中的db備份，是否都已歸位；雷已完成(可再次確認)'),
('2021-11-08'::date,'mgmt_weekly','主管會議',array[]::text[],'皓明 泰儀 泓儒 又仁 昭萱 黃杰 棠娜；見證後服務同意書>> 無須簽署；決議: >> 公告>> 黃杰'),
('2021-11-15'::date,'mgmt_weekly','主管會議',array[]::text[],'皓明 泰儀 泓儒 昭萱 棠娜 于瑾；證人>> 可能有爭議；見證>> 整個所不能處理該案件'),
('2021-11-22'::date,'mgmt_weekly','主管會議',array[]::text[],'皓明 泰儀 泓儒 黃杰 昭萱 于瑾；網路>> 再次清查是否有律師見證>>；文章不再寫<律師證人>，只單純寫<證人>'),
('2021-12-06'::date,'mgmt_weekly','主管會議',array[]::text[],'皓明 泰儀 泓儒 于瑾 又仁 黃杰 棠娜；待辦事項>> 1101206週排程；待辦事項頁拆成兩頁'),
('2021-12-13'::date,'mgmt_weekly','主管會議',array[]::text[],'皓明 泰儀 泓儒 于瑾 又仁 黃杰 棠娜 昭萱 郁萱；請大家把各自/各部門待辦事項的<已完成>，確認後點選完畢>> 大家；當事人專屬雲端連結'),
('2021-12-20'::date,'mgmt_weekly','主管會議',array[]::text[],'皓明 泰儀 泓儒 于瑾 又仁 黃杰 棠娜 昭萱 郁萱 又仁；建立<捷徑>無法用<搜尋>方式，因此需要從當事人海中一個一個往下拉，且還需要等待跑的時間；也無法將<捷徑>先放到暫存區，再放入正確位置'),
('2022-01-03'::date,'mgmt_weekly','主管會議',array['皓明','泰儀','泓儒','于瑾','又仁','黃杰','棠娜'],'原定結論: >> 泰儀/主管律師；有無其他功能為: 當事人只能上傳、不能刪除?>> 無其他功能；1/3討論結論>>'),
('2022-01-10'::date,'mgmt_weekly','主管會議',array['皓明','泰儀','泓儒','于瑾','又仁','黃杰','昭萱','郁萱'],'111/1/10討論新功能；111/1/7已完成案件「關鍵字搜尋」功能。在案件內的「案件資訊」編輯「案件關鍵字」。；tag是聯集(and)概念'),
('2022-01-24'::date,'mgmt_weekly','主管會議',array['皓明','泰儀','泓儒','于瑾','又仁','黃杰','昭萱','郁萱','棠娜'],'「案件歷程統計」呈現方式，「已委任」、「自案」、「待追」欄位，以品牌分別顯示數量。；1/24本週完成關鍵字的確認；交由各部門律師（法務？）標記'),
('2022-02-07'::date,'mgmt_weekly','主管會議',array['皓明','泰儀','泓儒','黃杰','又仁','昭萱','郁萱','棠娜'],'「案件歷程統計」增加「指導出庭」：寫狀同仁以外的出庭律師，系統會將之歸類為「指導出庭」。；改為「單純出庭」；確認85010關鍵字：'),
('2022-02-14'::date,'mgmt_weekly','主管會議',array['皓明','泰儀','泓儒','黃杰','又仁','昭萱','郁萱','棠娜'],'重構「受理機關資訊」；「案號」必須依照年度、字、號的格式填寫。原本的案號大部分均已導入，如果未完成導入，打開編輯可以看到原本輸入的案號內容。；「機關名稱」改成下拉選單，如果單位名稱不在列表中（例如警察機關），可以直接在文字框中輸入單位名稱，再按下新增即可新增。'),
('2022-03-07'::date,'mgmt_weekly','主管會議',array['皓明','泰儀','泓儒','黃杰','昭萱','郁萱','棠娜'],'修改「委任率」頁面樣式；委任率統一使用藍色，委任數量使用黃色。；人員部分改為顯示「委任率」，並將人員移至最上面顯示。'),
('2022-03-14'::date,'mgmt_weekly','主管會議',array['泰儀','泓儒','黃杰','昭萱','郁萱','又仁'],'「側邊欄選單」樣式與階層的重構。；目前狀況: 點開第二層後，只要一有點選無法維持在第二層，此情況目前要修正較花時間，後續再追蹤。若有其他優化事項再請大家提出。；將人工輸入原始受理機關名稱，予以統一修正為正確的機關名稱。'),
('2022-03-21'::date,'mgmt_weekly','主管會議',array['泰儀','泓儒','黃杰','昭萱','又仁','皓明'],'更新「案件關鍵字」。；全站「案號」顯示均改為「xx年度x字第xx號」。；「人名下拉選單」移除已離職人員（仍可在網址中輸入人名搜尋）。'),
('2022-03-28'::date,'mgmt_weekly','主管會議',array['泰儀','泓儒','黃杰','昭萱','皓明','郁萱'],'「案件機構」下拉選單搜尋「台/臺」，都可以出現「臺」。；「案號搜尋」改名為「案號/機關搜尋」。；修正「代收代付」總金額計算錯誤。'),
('2022-04-11'::date,'mgmt_weekly','主管會議',array['泰儀','泓儒','黃杰','昭萱','皓明','郁萱','棠娜'],'本週原預計更新「律師查詢」功能，但目前因系統更新出現技術問題，尚未能完成。；緣由: 對造律師不該跟對造在同一格；另外對造律師應該可不用出現在總表(昭郁杰)，系統已另設定一個<對造律師>分頁，可讓大家維護對造律師評價與辦案品質。'),
('2022-05-02'::date,'mgmt_weekly','主管會議',array['泰儀','泓儒','黃杰','皓明','又仁'],'已完成「律師查詢」功能。；系統已另設定一個<對造律師>分頁，可讓大家維護對造律師評價與辦案品質。；請大家都填入<對造律師>，不再填寫<關係人>，待工程端確認系統可否一次性更新'),
('2022-05-09'::date,'mgmt_weekly','主管會議',array['泰儀','泓儒','黃杰','皓明','又仁','昭萱','郁萱'],'「案件搜尋」頁面，移除搜尋筆數限制，並改成分頁顯示。；Bug Fixes；將「行政事件」tag改成下拉選單，避免儲存時誤將「法院」勾選的問題。<< bug修正'),
('2022-05-16'::date,'mgmt_weekly','主管會議',array['泰儀','泓儒','皓明','又仁','昭萱'],'修復「案件歷程」點擊文本框時，下拉選單會跳回預設值的問題。。；系統排除重複名稱的關鍵字 何泓儒；北所>> 愷凌案件待產假結束後再請愷凌協助>> 0502: 改由燦鴻(愷凌)、景琴(珮珊)協助，但完成希望抓在兩個月後(6月底)。'),
('2022-05-30'::date,'mgmt_weekly','主管會議',array['泰儀','泓儒','皓明','又仁','昭萱','黃杰','郁萱'],'「對造律師」：在案件內增加「對造律師評論」功能，預設為該案件之 評價。；其他: 確認<余松永>有無記錄到對造律師(蘇萱)；「對造律師」：增加本所承辦案件列表。(亦可直接搜尋對造律師)'),
('2022-06-06'::date,'mgmt_weekly','主管會議',array['泰儀','泓儒','皓明','又仁','昭萱','桑羽','光星'],'新增會議記錄人員；新增是否簽約，避免與是否委任重複定義；諮詢後簽約者? 三諮後簽約?(會開三次諮詢的系統，最後一次諮詢的系統才會改為已簽約)'),
('2022-06-13'::date,'mgmt_weekly','主管會議',array['皓明','黃杰','昭萱','桑羽','杰峰'],'「諮詢」卡片添加「會議記錄」；「是否委任」改成「是否簽約」。；「機關人員搜尋」增加顯示「案件狀態」「備註」；內文對齊標題。；案件內「受理機關」->「機關人員」備註輸入框改大，備註顯示寬度增加。'),
('2022-06-20'::date,'mgmt_weekly','主管會議',array['皓明','黃杰','昭萱','桑羽','杰峰','又仁','泓儒','光星','泰儀','郁萱'],'新增「統計分析」->「客戶關係追蹤表」，可以查詢諮詢卡片上「接案人員」的數據。；（目前因效能限制，查詢時請勿超過兩個月，或是選擇太多接案人員）；與接案確認「已簽約」的邏輯'),
('2022-06-27'::date,'mgmt_weekly','主管會議',array['皓明','黃杰','昭萱','桑羽','杰峰','又仁','泓儒','光星','泰儀','郁萱'],'之前的統計是否需要修改?>> 待泓儒接案討論，目前可能不回補? 誤差拉出來檢查?>> 接案部門手動調整；案件狀態 - 已委任 -> 已分案辦理中（請律師確認合適用詞）；未簽約/已簽約未付款/已簽約事務所分期付款/已簽約貸款分期付款/已簽約已付清'),
('2022-07-03'::date,'mgmt_weekly','主管會議',array['皓明','黃杰','昭萱','桑羽','又仁','泓儒','泰儀','郁萱','光星','杰峰'],'「委任率」頁面改為「簽約率」；原本人員搜尋從「案件接案同仁」改為「諮詢卡片」的「接案同仁」。；「委任率」改名為「簽約率」。'),
('2022-07-11'::date,'mgmt_weekly','主管會議',array['皓明','黃杰','昭萱','桑羽','又仁','泓儒','泰儀','光星','杰峰'],'「客戶追蹤表」更新；協助接案部門為主；各主管可觀察，<可排序、可filter的功能>是否其他頁面也需要?'),
('2022-07-17'::date,'mgmt_weekly','主管會議',array['皓明','黃杰','昭萱','桑羽','又仁','泓儒','泰儀','光星','杰峰','郁萱'],'「委任率」頁面更新。>> 新增"%"，避免誤會成"件數"，而非"%數"；添加「委任率」與「簽約率」。；頁面上方添加「使用說明」與「數據定義」說明。'),
('2022-07-25'::date,'mgmt_weekly','主管會議',array['皓明','黃杰','昭萱','桑羽','又仁','泓儒','泰儀','光星','杰峰','郁萱'],'新增「對帳資訊」beta版。；「代收代付對帳」添加下載csv功能。；修正「客戶關係業績表」，移除作廢資料，新增諮詢業績加總。'),
('2022-08-01'::date,'mgmt_weekly','主管會議',array['皓明','黃杰','昭萱','桑羽','又仁','泓儒','泰儀','光星','杰峰','郁萱'],'<對帳資訊beta>；接案所 接案/退款 數據 可交互聯集；代收代付對帳 新增<下載連結> 以利會計系統與專案管理系統連結'),
('2022-08-08'::date,'mgmt_weekly','主管會議',array['皓明','黃杰','昭萱','桑羽','又仁','泓儒','泰儀','光星','杰峰','郁萱'],'「對帳資訊beta」添加客戶來源。；修正「人工利衝」備註沒換行問題。；修正「代收代付」日期未轉時區的問題（原本保存後會-8小時）。'),
('2022-08-15'::date,'mgmt_weekly','主管會議',array['皓明','黃杰','昭萱','桑羽','又仁','泓儒','泰儀','光星','郁萱'],'法務均已到職，預計8月底處理完畢。；預設”尚未填寫”；可搜尋”尚未標記”關鍵字的頁面調整'),
('2022-08-22'::date,'mgmt_weekly','主管會議',array['皓明','黃杰','昭萱','桑羽','又仁','泓儒','泰儀','光星','杰峰'],'專案管理系統使用說明書>>；可搜尋”尚未標記”關鍵字的頁面調整>> 0822週上線；資料檢查 icon: manually-entered-data'),
('2022-08-29'::date,'mgmt_weekly','主管會議',array['皓明','黃杰','昭萱','又仁','泓儒','光星','杰峰','郁萱'],'可搜尋”尚未標記”關鍵字的頁面調整>> 0905週上線 (@泓儒評估後續時程)；新增法官評價機制>> 0829週上線；法官：姓名、當前機關(兩層)、股別、備註'),
